package com.restaurantcraft.screen; import com.restaurantcraft.menu.CustomerOrderMenu; import com.restaurantcraft.network.C2SSubmitDishPacket; import com.restaurantcraft.registry.ModPackets; import net.minecraft.client.gui.GuiGraphics; import net.minecraft.client.gui.components.Button; import net.minecraft.client.gui.screens.inventory.AbstractContainerScreen; import net.minecraft.network.chat.Component; import net.minecraft.world.entity.player.Inventory; public class CustomerOrderScreen extends AbstractContainerScreen<CustomerOrderMenu>{ public CustomerOrderScreen(CustomerOrderMenu m, Inventory i, Component t){super(m,i,t);} protected void init(){super.init();addRenderableWidget(Button.builder(Component.translatable("button.restaurant_craft.submit"),b->ModPackets.sendToServer(new C2SSubmitDishPacket(menu.customerId))).bounds(leftPos+62,topPos+58,52,20).build());} public void render(GuiGraphics g,int mx,int my,float pt){renderBackground(g);super.render(g,mx,my,pt);renderTooltip(g,mx,my);} protected void renderBg(GuiGraphics g,float p,int mx,int my){g.fill(leftPos,topPos,leftPos+imageWidth,topPos+imageHeight,0xCC303030);g.drawString(font,Component.translatable("screen.restaurant_craft.customer_order"),leftPos+8,topPos+8,0xFFFFFF,false);} }
